int _transactionEstimateSize(
  Transaction object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  bytesCount += 3 + object.account.length * 3;
  bytesCount += 3 + object.currency.length * 3;
  bytesCount += 3 + object.deviceId.length * 3;
  bytesCount += 3 + object.memo.length * 3;
  bytesCount += 3 + object.platform.length * 3;
  bytesCount += 3 + object.type.length * 3;
  return bytesCount;
}

void _transactionSerialize(
  Transaction object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeString(offsets[0], object.account);
  writer.writeDouble(offsets[1], object.amount);
  writer.writeString(offsets[2], object.currency);
  writer.writeDateTime(offsets[3], object.date);
  writer.writeString(offsets[4], object.deviceId);
  writer.writeString(offsets[5], object.memo);
  writer.writeString(offsets[6], object.platform);
  writer.writeString(offsets[7], object.type);
}

Transaction _transactionDeserialize(
  Id id,
  IsarReader reader,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  final object = Transaction();
  object.account = reader.readString(offsets[0]);
  object.amount = reader.readDouble(offsets[1]);
  object.currency = reader.readString(offsets[2]);
  object.date = reader.readDateTime(offsets[3]);
  object.deviceId = reader.readString(offsets[4]);
  object.id = id;
  object.memo = reader.readString(offsets[5]);
  object.platform = reader.readString(offsets[6]);
  object.type = reader.readString(offsets[7]);
  return object;
}

